def summarize(title, *args, **kwargs):
    print(title)
    for point in args:
        print(f"- {point}")
    for key, value in kwargs.items():
        print(f"{key}: {value}")

summarize(
    "My Report",
    "Sales up 10%",
    "New markets opened",
    author="Alice",
    date="2026-07-02"
)
